struct cmp { //重载 3
	bool operator()(node &a,node&b) {
		int na=0,nb=0;
		for(int i=0; i<25; i++) {
			if(a.s[i]!=ans[i]) na++;
			if(b.s[i]!=ans[i]) nb++;
		}
		return na+a.step>nb+b.step;
	}
};
unordered_map<string,bool>mp;

void bfs(node t) {
	//priority_queue<node,vector<node>,node>q; //重载 1
	priority_queue<node,vector<node>,cmp>q;//重载 3
	//priority_queue<node>q; //重载 2
	q.push(t);
	while(q.size()) {
		node x=q.top(),y=x;
		q.pop();
		for(int i=0; i<8; i++) {
			int dx=x.pos/5+kd[i][0],dy=x.pos%5+kd[i][1];
			if(dx<0||dx>4||dy<0||dy>4) continue;
			swap(x.s[x.pos] , x.s[dx*5+dy]);//交换一次
			int num=0;
			for(int j=0; j<25; j++) { //优化
				if(x.s[j]!=ans[j]) num++;
			}
			if(num+x.step>15) {
				x=y;//swap(x.s[x.pos] , x.s[dx*5+dy]);//交换一次;
				continue;
			}
			x.pos=dx*5+dy;
			x.step++;
			if(mp[x.s]==0) { //如果没有出现
				if(x.step>15) {
					cout<<-1<<endl;
					return;
				}
				if(x.s==ans) {
					cout<<x.step<<endl;
					return;
				}
				mp[x.s]=1;
				q.push(x);
			}
			x=y;
		}
	}
	cout<<"-1"<<endl;
}
int main() {
	ios::sync_with_stdio(0);
	cin.tie(0),cout.tie(0);

	cin>>T;
	while(T--) {
		node x;
		mp.clear();
		string str;
		for(int i=0; i<5; i++) {
			cin>>str;
			x.s+=str;
		}
		x.step=0;
		x.pos=x.s.find('*');
		mp[x.s]=1;
		bfs(x);
	}
	return 0;
}
